class Solution {
public:
    int minimizeXor(int num1, int num2) {
        int count = 0;
        while (num2) {
            num2 >>= 1;
            count++;
        }
        int res = 0;
        for (int i = 0; i < count; i++) {
            if ((num1 >> i) & 1) {
                res |= 1 << i;
            }
        }
        return res;
    }
};
